var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"20여 년 전, 관리실패라는 거대한 재해가 일어났다.","JPN":"約20年前、管理失敗という巨大な災害が発生した。","ENG":"20 years ago, a colossal disaster called Administration Failure occurred.","TWN":"二十年前，發生過一場管理失敗的巨大災難。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"많은 사람이 죽었고, 많은 터전이 사라졌다고 한다.","JPN":"多くの人が命を落とし、多くの家屋が消えたという。","ENG":"Many people died, and many more lost their homes.","TWN":"據說，當時很多人死掉，大片的房屋被損毀。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"바닷가의 사람들도 예외는 아니었다.","JPN":"海辺の人々も例外ではなかった。","ENG":"People near the sea were no exception.","TWN":"連海邊的人們也不例外。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"문명의 잔해 위에 남겨진 생존자들에게 법은 무색했고, 그 사이에선 범죄가 아무렇지 않게 일어났다.","JPN":"文明の残骸の上に残された生存者に法は存在価値をなくし、その狭間では犯罪が蔓延っていた。","ENG":"Law became meaningless for the survivors standing on the rubble of civilization, with criminal activity happening all throughout.","TWN":"對於被遺留在文明廢墟上的倖存者而言，法律形同虛設，在那段時期裡，犯罪不會受到任何應有的懲罰。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"그중 대부분은 가진 자의 것을 훔치는 범죄가 아닌, 서로의 생존권을 건 빈자들의 싸움이었다.","JPN":"そのほとんどは富める者から盗む犯罪ではなく、互いの生存権をかけた貧しい者たちの戦いだった。","ENG":"However, most of the crimes were not about stealing from the rich, but about the poor fighting for their lives.","TWN":"其中大部分的犯罪，不是劫富濟貧，而是窮人之間為生存而發生的鬥爭。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"그 처절한 싸움을 처음으로 중재했던 건, 정부도, 관리국도 아닌…","JPN":"その凄絶な戦いを最初に仲裁したのは、政府でも管理局でもなく……","ENG":"The first to intervene and mediate the fights was not the government nor the Administration...","TWN":"然而平息那場慘烈鬥爭的，既不是政府，也不是管理局…"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":null,"text":{"KOREA":"바다의 무법자들이었다.","JPN":"海の無法者たちだった。","ENG":"But the outlaws of the sea.","TWN":"而是一群海上的不法之徒。"},"stage":{"bg":"FRONTBAY_03","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":null,"text":{"KOREA":"더 이상 훔칠 게 아무것도 남지 않은 해적은 누구도 원치 않는 바다로 나아가 침식체들을 사냥하기 시작했다.","JPN":"もう盗むものが何も残っていなかった海賊は、誰もが好まない海に出て侵食体を狩り始めた。","ENG":"Once there was nothing left to steal on land, the pirates set sail for the seas that no one wanted to traverse and started hunting C.O.s.","TWN":"偷無可偷的海盜們，揚帆出航，去到無人願意踏足的大海之上，展開狩獵侵蝕體的日子。"},"stage":{"bg":"FRONTBAY_03","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":null,"text":{"KOREA":"그 대가로 사람들에게 보호비를 받았지만, 사람들은 침식체의 위협으로부터 벗어난 삶을 되찾기 위해 마땅한 대가를 치렀다.","JPN":"その対価として人々から保護費をもらったが、人々は侵食体の脅威から逃れた暮らしを取り戻すため、それ相応の対価を払った。","ENG":"In return for their services, these pirates collected protection fees, which the people gladly paid to reclaim their lives from the threats of C.O.s.","TWN":"雖然他們因此向大家索討保護費作為回報。但只要能免於受到侵蝕體的威脅，人們也不在乎這一點代價。"},"stage":{"bg":"FRONTBAY_03","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":null,"text":{"KOREA":"잃어버린 고향을 점차 수복하기 시작하면서, 사람들은 내일이라는 희망을 품게 되었다.","JPN":"次第に失った故郷が修復し始め、人々は明日という希望を抱くようになった。","ENG":"As the ruins of their hometown were gradually reconstructed, the people started becoming hopeful for a brighter tomorrow.","TWN":"隨著人們逐漸開始重建失去的家園，他們開始對明天充滿希望。"},"stage":{"bg":"FRONTBAY_03","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":null,"text":{"KOREA":"해적이 권력을 갖게 되면서, 자연스레 범죄자들은 권력의 통제를 따르기 시작했다.","JPN":"海賊が権力を持つようになり、自然と犯罪者たちは権力の統制に従い始めた。","ENG":"Also, the pirates began gaining power, and the rest of the criminals submitted under their control.","TWN":"海盜得勢後，罪犯自然也開始屈服於他們。"},"stage":{"bg":"FRONTBAY_03","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":null,"text":{"KOREA":"대균열 이후 무너졌던 질서가 돌아오기 시작한 것이다.","JPN":"大亀裂以後、崩れた秩序が戻りつつあったのだ。","ENG":"The order that collapsed after the Grand Dimension Crevice was being restored.","TWN":"大峽谷之後，曾經瓦解的秩序開始回到正軌。"},"stage":{"bg":"FRONTBAY_03","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":null,"text":{"KOREA":"아이러니하게도 그 질서의 중심에는 해적이 있었다.","JPN":"皮肉にも、その秩序の中心には海賊がいた。","ENG":"And the irony behind it was that a pirate was at the core of this so-called order.","TWN":"諷刺的是，這個秩序的核心是一名海盜。"},"stage":{"bg":"FRONTBAY_03","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":null,"text":{"KOREA":"사람들은 그 해적의 이름을 기꺼이 존경하며, 이렇게 불렀다.","JPN":"人々はその海賊の名前を喜んで尊敬し、こう呼んだ。","ENG":"The people willingly respected this pirate's name and called him...","TWN":"人們尊敬欽佩他，尊敬地稱呼他為，"},"stage":{"bg":"FRONTBAY_03","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":null,"text":{"KOREA":"대해적. 에이버리.","JPN":"大海賊、エイバリー。","ENG":"The Great Pirate, Avery.","TWN":"大海盜艾維利。"},"stage":{"bg":"FRONTBAY_03","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":null,"text":{"KOREA":"들리시나요? 듣고 계시면 대답해주세요. 시니어님!","JPN":"聞こえますか？　聞いているのなら、答えてください。シニア様！","ENG":"Do you copy? Sir, please answer if you can hear me!","TWN":"聽得到嗎？聽到請回答，Senior！"},"stage":{"bg":"BLACK","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_RAIN_02"},{"id":"L25_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>그래, 날 찾았나?</color>","JPN":"<color=#ffd34c>ああ、私を呼んだか？</color>","ENG":"<color=#ffd34c>I hear you. You're looking for me?</color>","TWN":"<color=#ffd34c>嗯，你找我？</color>"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"대체 어디 계신 건가요? 며칠째 자릴 비우시고, 소식도 없고!","JPN":"いったいどこにいるのですか？　何日も不在で、何の連絡もないなんて！","ENG":"Where are you? You have been gone for days without sending any word!","TWN":"你到底跑去哪裡？消失這麼多天，一點消息都沒有！"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"방금 이 통신라인을 찾으려고 제가 전산추적기능을 얼마나 낭비했는지 아세요?!","JPN":"この通信ラインを探すのに、私がどれだけのトラッキング機能を無駄にしたかわかりますか！？","ENG":"Do you know how much of my computer tracking function was wasted trying to find this comms line?!","TWN":"你知道為了找到這條通訊線路，耗費多少電腦追蹤的功能嗎？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"지금 프론트베이에 어떤 일이 벌어지고 있는지 아시냐고요!","JPN":"今フロントベイに何が起きているのか、わかっているのですか！","ENG":"Are you even aware of what is happening in Front Bay right now?!","TWN":"你知道現在前灣發生什麼事嗎？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_HATE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>그래.</color>","JPN":"<color=#ffd34c>ああ。</color>","ENG":"<color=#ffd34c>I do.</color>","TWN":"<color=#ffd34c>嗯。</color>"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L31_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>이대로라면, 검은 범람이 격벽을 넘어 프론트베이를 집어삼키겠지.</color>","JPN":"<color=#ffd34c>このままでは、黒い氾濫が隔壁を越えてフロントベイを飲み込むだろう。</color>","ENG":"<color=#ffd34c>At this rate, the Black Flood will go over the bulwark and swallow Front Bay.</color>","TWN":"<color=#ffd34c>再這樣下去，黑色洪災會衝破隔離牆吞噬整個前灣。</color>"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>20년 전 반으로 잘린 크라켄이 이젠 두 배로 더 거대해져서 나타났으니 말이야.</color>","JPN":"<color=#ffd34c>20年前に真っ二つになったクラーケンが、今は2倍とさらに大きくなって現われたからな。</color>","ENG":"<color=#ffd34c>It's been 20 years since Kraken was cut in half. Now, it's back, and it's grown twice in size.</color>","TWN":"<color=#ffd34c>二十年前被劈成兩半的克拉肯，現在已經是當初的二倍大。</color>"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"그걸 아시는 분이 지금까지 아무런 대처도 없이 연락을 끊고 있었던 건가요?!","JPN":"それをわかっているのに、今まで何の対処もせず連絡も断っていたのですか！？","ENG":"You knew all along, and yet you decided to go off grid without any countermeasures?!","TWN":"你既然知道，為什麼不採取任何措施，還搞消失？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>그건 내가 비서관을 믿고 있기 때문이지.</color>","JPN":"<color=#ffd34c>それは私が秘書官を信じていたからだ。</color>","ENG":"<color=#ffd34c>That's because I believed in my secretary.</color>","TWN":"<color=#ffd34c>那是因為我信任秘書。</color>"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>자네처럼 유능한 인공지능은 두 번 다시 못 찾을 테니까.</color>","JPN":"<color=#ffd34c>君ほど有能な人工知能は二度と探せないからな。</color>","ENG":"<color=#ffd34c>I won't be able to find another competent AI like you.</color>","TWN":"<color=#ffd34c>像你這麼能幹的人工智慧根本世間南尋。</color>"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"그동안 대체 밖에서 뭘 하고 계셨던 거죠?","JPN":"今まで、外でいったい何をしていたのですか？","ENG":"What have you been doing all this time anyway?","TWN":"這段時間你到底都在外面幹什麼？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>내가 전에 했던 얘기 기억하나?</color>","JPN":"<color=#ffd34c>前に私がした話は覚えてるか？</color>","ENG":"<color=#ffd34c>Remember what I said to you a while ago?</color>","TWN":"<color=#ffd34c>還記得我之前說過的話嗎？</color>"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"네, 시니어님의 말씀은 하나도 빼놓지 않고 기록하고 있으니까요.","JPN":"はい、シニア様のお言葉は一つも漏らさず記録していますので。","ENG":"Yes. I record everything you say, sir.","TWN":"嗯，Senior說的每句話，我都有一字不漏地記下來。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>크라켄이 몸을 완전히 수복하게 되면, 검은 범람은 격벽으로 막을 수 없을 거라고 했었지.</color>","JPN":"<color=#ffd34c>クラーケンが体を完全に修復したら、黒い氾濫は隔壁で止められないと言ったはずだ。</color>","ENG":"<color=#ffd34c>I told you that if Kraken fully recovers, the bulwark won't be enough to stop the Black Flood.</color>","TWN":"<color=#ffd34c>你說過，一旦克拉肯的身體完全恢復，隔離牆將無法阻擋黑色洪災。</color>"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"그래서, 저희는 다음 검은 범람을 막기 위한 계획을 세웠죠.","JPN":"ですから、私たちは次の黒い氾濫を止めるための計画を立てたのです。","ENG":"And that is why we set up a plan to stop the next Black Flood.","TWN":"因此，我們才想出一個阻止下一次黑色洪災的計畫。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>그리고 그 계획은… 예정된 기한에 맞추지 못할 수도 있다고도 했었고.</color>","JPN":"<color=#ffd34c>そしてその計画は……予定された期限に間に合わない可能性もあると言ったな。</color>","ENG":"<color=#ffd34c>And I also mentioned that the plan... might not be completed within time.</color>","TWN":"<color=#ffd34c>我還說過，那個計畫…可能無法如期完成。</color>"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"시니어님께서 플랜B에 대해 말씀하신 것도 그것 때문이었죠.","JPN":"シニア様がプランBについてお話したのも、それのせいでしたね。","ENG":"Which is also why you suggested a plan B, sir.","TWN":"這就是Senior所說的B計畫吧。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>크라켄은… 현재로서는 격퇴가 가능한 녀석이 아니야.</color>","JPN":"<color=#ffd34c>クラーケンは……今のところ撃退できるヤツではない。</color>","ENG":"<color=#ffd34c>Kraken is... not something we can defeat at the moment.</color>","TWN":"<color=#ffd34c>克拉肯…目前還不是一個可以戰勝的傢伙。</color>"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L50_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>설령 녀석을 처치한다 해도, 녀석이 몸으로 틀어막고 있던 거대한 균열이 또다른 골칫거리를 불러들이겠지.</color>","JPN":"<color=#ffd34c>たとえヤツを片付けたとしても、ヤツが体で塞いでいた巨大な亀裂がまた別の問題を招くだろう。</color>","ENG":"<color=#ffd34c>Even if we somehow do, the huge crevice its body was blocking will cause more problems.</color>","TWN":"<color=#ffd34c>即使你成功打敗他，他所阻擋的巨大裂縫也會是另一件棘手的事情。</color>"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>놈에게 쉽게 회복하지 못할 부상을 입혀 시간을 버는 게 현재로서는 최선책이야.</color>","JPN":"<color=#ffd34c>ヤツに簡単には回復できない傷を負わせ時間を稼ぐのが、今はベストだ。</color>","ENG":"<color=#ffd34c>The best thing we can do right now is to wound it so and buy us more time.</color>","TWN":"<color=#ffd34c>我們目前最好的辦法，就是對他造成難以恢復的傷害，盡量拖延時間。</color>"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"하지만 심해에 숨어 있는 괴물에게 그 정도의 타격을 입히는 건 쉽지 않은 과제입니다.","JPN":"ですが、深海に隠れている化け物にそのようなダメージを与えることは、簡単ではないミッションです。","ENG":"However, damaging a monster hiding in the depths of the ocean is no easy task.","TWN":"但是，要對潛伏在海洋深處的怪物造成如此大的傷害可不是件容易的事。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"제 아무리 강한 카운터나 함선을 데려간다 해도, 본체에 타격을 주지 못하면 의미가 없어요.","JPN":"いくら強いカウンターや艦船を動員したとしても、本体にダメージを与えないかぎり意味がありません。","ENG":"Even if we bring a powerful Counter or ship, it will be in vain if we cannot hurt the body.","TWN":"如果無法攻擊他的本體，不管有多少制裁者或艦船都沒用。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>그러니, 놈의 머리를 끌어내야지.</color>","JPN":"<color=#ffd34c>だから、ヤツの頭を引っ張り出すのだ。</color>","ENG":"<color=#ffd34c>That's why we have to lure out its head.</color>","TWN":"<color=#ffd34c>所以，讓我們把他引出來吧。</color>"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L8_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"설마… 그 때처럼 미끼를 자처하시려고요?","JPN":"まさか……あの時のように、オトリになるつもりですか？","ENG":"Are you... volunteering as bait like last time?","TWN":"該不會…他還會像當時那樣上鉤嗎？"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"기함 인빈서블이 있던 20년 전이면 몰라도, 10년 뒤에 출현했던 크라켄을 제압했던 건 펜릴 소대처럼 강력한 전력이 함께였기 때문이었어요!","JPN":"旗艦インビンシブルがあった20年前ならともかく、その10年後に現われたクラーケンを制圧したのは、フェンリル小隊のような強力な戦力が一緒だったからです！","ENG":"It's not 20 years ago when you still had your flagship, Invincible, or 10 years ago when you had the help of Fenrir Squad!","TWN":"二十年前，還有旗艦無敵號，但要對付十年後的克拉肯，需要擁有堪比芬里爾小隊這樣強大的力量才行！"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"예전보다 더 거대하고 강해진 크라켄을 지금의 시니어님 혼자서 제압할 수 없다는 거 잘 아시잖아요!","JPN":"昔よりもっと巨大で強力になったクラーケンを、今のシニア様が一人では制圧できないというのは、よくわかっていることではないですか！","ENG":"Kraken is now bigger and stronger! You know well that you cannot defeat it by yourself now!","TWN":"克拉肯比以往任何時候都要更大、更強，只靠Senior你一人，是無法制服他的！"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>난 혼자가 아니야.</color>","JPN":"<color=#ffd34c>私は一人ではない。</color>","ENG":"<color=#ffd34c>But I'm not by myself.</color>","TWN":"<color=#ffd34c>不止我一人。</color>"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>프론트베이엔 바다를 지키고, 침식체를 쫓는 수많은 사냥꾼이 있지 않나?</color>","JPN":"<color=#ffd34c>フロントベイには海を守り、侵食体を追う数多くのハンターがいるだろう？</color>","ENG":"<color=#ffd34c>Front Bay has numerous hunters who chase away C.O.s and protect the sea, right?</color>","TWN":"<color=#ffd34c>前灣不是有一大群獵人在守護著海洋，驅逐侵蝕體嗎？</color>"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"돈을 위해 일하는 이익집단일 뿐이겠죠! 그들이 서로 협력할 가능성은 없다고 봐도 무방합니다!","JPN":"彼らはお金のために働いている利益集団にすぎません！　互いに協力する可能性はないも同然です！","ENG":"They are merely in it for the money! It is safe to say that their cooperation is highly unlikely!","TWN":"他們不過是群唯利是圖的人！他們不可能齊心合作的！"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"게다가 상대가 크라켄이라면 겁에 질려 싸우려고도 하지 않을 거예요!","JPN":"しかも相手がクラーケンなら、怖気づいて戦おうともしないはずです！","ENG":"On top of that, all of them will flee if they're faced with Kraken!","TWN":"何況，要對付的是克拉肯，他們肯定不敢的！"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>뭐든 처음이 어려운 법이야, 벨라미.</color>","JPN":"<color=#ffd34c>何事も最初が難しいのだ、ベラミー。</color>","ENG":"<color=#ffd34c>It's always the first time that's hard, Bellamy.</color>","TWN":"<color=#ffd34c>第一次是最難的，貝拉米。</color>"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>인간은 그게 가능하다는 걸 아는 순간, 무궁무진한 추진력을 얻게 되거든.</color>","JPN":"<color=#ffd34c>人間はそれができると知った瞬間、限りない推進力を得ることになる。</color>","ENG":"<color=#ffd34c>But once humans figure out that it's possible, that's when we start to gain incredible momentum.</color>","TWN":"<color=#ffd34c>當人類意識到可能性，他們就會擁有強大的力量。</color>"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"QM_MARK_ANY_NOIMAGE","text":{"KOREA":"난 내일 협력자들과 함께 심해역으로 향해 플랜B를 이행할 계획이라네.","JPN":"私は明日協力者たちと一緒に深海域に向かい、プランBに移行する計画だ。","ENG":"Tomorrow, I'm setting sail with my partners to the deep sea area to carry out our plan B.","TWN":"明天，我將和我的幫手們一起前往深水域，實施B計畫。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>프론트베이에는 시니어님이 필요합니다!</color>","JPN":"<color=#ffd34c>フロントベイにはシニア様が必要です！</color>","ENG":"<color=#ffd34c>Sir! But Front Bay needs its Senior!</color>","TWN":"<color=#ffd34c>前灣需要Senior！</color>"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L21_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>낭만 타령 하며 목숨을 걸어대는 해적이 아니라, 프론트베이를 이끌 리더가 필요한 거라고요!</color>","JPN":"<color=#ffd34c>ロマンを常套句に命をかける海賊ではなく、フロントベイを率いるリーダーが必要なのですよ！</color>","ENG":"<color=#ffd34c>Not some pirate who risks his life for the so-called pirate's dream, but someone to lead Front Bay!</color>","TWN":"<color=#ffd34c>前灣需要一個可以領導前灣的領導者，而不是一個冒著生命危險的浪漫主義海盜！</color>"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"QM_MARK_ANY_NOIMAGE","text":{"KOREA":"…프론트베이는 벨라미 양에게 부탁하지.","JPN":"……フロントベイはベラミー君に頼むとしよう。","ENG":"...I'll leave Front Bay's safety in your hands, Bellamy.","TWN":"…前灣就交給貝拉米了。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"QM_MARK_ANY_NOIMAGE","text":{"KOREA":"2급 관리자의 명령코드는 자네에게 맡기겠어.","JPN":"2級管理者の命令コードは、君に任せる。","ENG":"I'll delegate my Class 2 Administrator authorization code to you.","TWN":"我現在把2級管理者的指令代碼交給你。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>뭐라고요?! 잠깐만요!</color>","JPN":"<color=#ffd34c>何とおっしゃいました！？　待ってください！</color>","ENG":"<color=#ffd34c>What?! Now hold on a minute!</color>","TWN":"<color=#ffd34c>你說什麼？！等等！</color>"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"QM_MARK_ANY_NOIMAGE","text":{"KOREA":"손님들이 오는군. 그럼 이만 끊지.","JPN":"客が来たな。では、失礼しよう。","ENG":"Looks like I have some guests to attend to. I gotta go.","TWN":"有客人來了，我就不打擾你們了。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"PIRATE_FRONTBAY_NULL_LOOK","text":{"KOREA":"어이, 어떻게 돼 가는 거야? 서둘러!","JPN":"おい、どうなってんだ？　急げ！","ENG":"Hey, what's taking so long? Hurry up!","TWN":"喂，還沒好嗎？抓緊時間！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"PIRATE_FRONTBAY_NULL_STEAL","text":{"KOREA":"조금 기다려. 아직 잔뜩 담는 중이니까.","JPN":"ちょっと待ってろよ。まだまだ詰め込めるんだから。","ENG":"Be patient. There's still much to steal here.","TWN":"再等等，還能再裝一點。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIRATE_FRONTBAY_NULL_STEAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"PIRATE_FRONTBAY_NULL_STEAL","text":{"KOREA":"크헤헤, 보물을 가져왔다고 동네방네 소문내 놓곤 배에 그대로 내버려 두다니.","JPN":"クヘヘ、宝を持って来たことをそこいらじゅうに触れまわって、そのまま船に放置するなんてな。","ENG":"Kehehe... He boasted all over town how he brought back treasure, and he decided to just leave them on his ship.","TWN":"嘿嘿，那麼多人都知道他把寶藏代回來，竟然還敢把寶藏留在船上。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"PIRATE_FRONTBAY_NULL_STEAL","face":"UNIT_LAUGH"}}}},{"id":"L33_1","type":"dialog","speaker":"PIRATE_FRONTBAY_NULL_STEAL","text":{"KOREA":"보물사냥꾼 녀석, 지금쯤 곯아떨어져 있겠지? 용감한 만큼 멍청하구만.","JPN":"トレジャーハンターの奴、今頃眠りこけてるだろ？　勇敢な分、バカなんだな。","ENG":"That treasure hunter, I bet he's passed out on the ground about now, eh? He's as stupid as he is courageous, I tell ya.","TWN":"那個寶藏獵人，現在應該正在呼呼大睡吧？有勇無謀的笨蛋。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIRATE_FRONTBAY_NULL_STEAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"PIRATE_FRONTBAY_NULL_STEAL","text":{"KOREA":"보물이 잔뜩 묻혀 있다던 심해역의 전설이 사실이었어.","JPN":"宝がいっぱい埋められてるっていう深海域の伝説は本当だったんだ。","ENG":"Guess the legend was true about the deep sea area being riddled with buried treasure.","TWN":"看來深海域的傳說是真的，那裡埋著寶藏。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIRATE_FRONTBAY_NULL_STEAL","face":"UNIT_PRIDE"},"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"PIRATE_FRONTBAY_NULL_STEAL","text":{"KOREA":"자루 하나만 채워도 평생 떵떵대며 살 수 있을 거라고.","JPN":"満杯に詰めた一袋だけも、一生遊んで暮らしていけるぞ。","ENG":"One sack full of loot is enough to last us a lifetime!","TWN":"光這滿滿的一袋，應該夠我快活一輩子吧。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIRATE_FRONTBAY_NULL_STEAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"PIRATE_FRONTBAY_NULL_LOOK","text":{"KOREA":"야, 야! 누가 온다! 얼른 숨어!","JPN":"お、おい！　誰か来る！　早く隠れろ！","ENG":"Hey, hey! Someone's coming! Hide!","TWN":"喂，喂！有人來了！快躲起來！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIRATE_FRONTBAY_NULL_STEAL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_METAL_KNOCK"},{"id":"L38_1","type":"dialog","speaker":"PIRATE_FRONTBAY_NULL_STEAL","text":{"KOREA":"뭣? 이 오밤중에 갑자기…?!","JPN":"は？　こんな真夜中に突然……！？","ENG":"Huh? At this late hour...?!","TWN":"什麼？半夜三更的，怎麼突然…？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIRATE_FRONTBAY_NULL_STEAL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"HUNTER_FRONTBAY_NULL_DOUBT","text":{"KOREA":"지키고 있는 녀석 없지?","JPN":"見張ってる奴、いないだろうな？","ENG":"No one was guarding it, right?","TWN":"沒人看守嗎？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HUNTER_FRONTBAY_NULL_DOUBT","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"HUNTER_FRONTBAY_NULL_SCARED","text":{"KOREA":"그래. 실어 나르는 건 못 봤으니까 보물은 분명 이 배 안에 있을 거야.","JPN":"ああ。運び出す姿は見てねえから、宝はきっとこの船の中だ。","ENG":"Yeah. I didn't see anyone carry anything out, so the treasure must still be on the ship.","TWN":"對，我沒看到他們卸貨，所以寶藏一定還在這艘船上。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HUNTER_FRONTBAY_NULL_DOUBT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HUNTER_FRONTBAY_NULL_SCARED","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"HUNTER_FRONTBAY_NULL_DOUBT","text":{"KOREA":"문은? 열 방법 있어?","JPN":"扉は？　開ける方法はあるのか？","ENG":"What about the door? Is there a way to open it?","TWN":"你有辦法打開門嗎？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HUNTER_FRONTBAY_NULL_DOUBT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HUNTER_FRONTBAY_NULL_SCARED","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"HUNTER_FRONTBAY_NULL_SCARED","text":{"KOREA":"잠깐만, 토치를 가져왔었는데…","JPN":"ちょっと待てよ、たいまつを持っていたんだ……","ENG":"Hold on, where's the blowtorch I brought...","TWN":"等等，我明明有帶噴槍…"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HUNTER_FRONTBAY_NULL_DOUBT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HUNTER_FRONTBAY_NULL_SCARED","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"HUNTER_FRONTBAY_NULL_SCARED","text":{"KOREA":"응? 문이 안 잠겨 있잖아? 그냥 열리는데?","JPN":"うん？　ドアが開いてる？　そのまま開いたんだけど。","ENG":"Hmm? It's not even locked. It just opens.","TWN":"嗯？門沒鎖？一推就開了？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HUNTER_FRONTBAY_NULL_DOUBT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HUNTER_FRONTBAY_NULL_SCARED","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"HUNTER_FRONTBAY_NULL_DOUBT","text":{"KOREA":"그게 무슨 소리야? 설마 선수친 녀석들이 있는 건가?","JPN":"どういうことだ？　まさか、先に来た奴らがいるのか？","ENG":"What the hell is that supposed to mean? Did someone already loot it before us?","TWN":"你說什麼？難道被人搶先一步？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HUNTER_FRONTBAY_NULL_DOUBT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HUNTER_FRONTBAY_NULL_SCARED","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"HUNTER_FRONTBAY_NULL_SCARED","text":{"KOREA":"아니, 그건 아니야. 안에 보물이 그대로 있어.","JPN":"いや、それは違う。中に宝がそのまま残ってる。","ENG":"No, I don't think so. The treasure's still all there.","TWN":"沒事，寶藏還在裡面。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HUNTER_FRONTBAY_NULL_SCARED","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"HUNTER_FRONTBAY_NULL_DOUBT","text":{"KOREA":"우오옷, 척 봐도 귀해 보이는 것들이 잔뜩 있잖아?","JPN":"うほお、パッと見ても高そうなものがいっぱいあるじゃねえか？","ENG":"Ooh! Look at all the shiny things piled up!","TWN":"喔喔！這些東西一看就很值錢呢！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HUNTER_FRONTBAY_NULL_DOUBT","face":"UNIT_IDLE"},"C":{"char_id":"HUNTER_FRONTBAY_NULL_SCARED","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"HUNTER_FRONTBAY_NULL_SCARED","text":{"KOREA":"함정 아냐? 경계가 너무 허술해. 불침번도 없고.","JPN":"ワナじゃない？　監視が緩すぎる。門番もいねえし。","ENG":"What if it's a trap? I mean, seeing how it's just laid out for us without any security...","TWN":"不會是陷阱吧？戒備如此鬆散，連個看守的人也沒有。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HUNTER_FRONTBAY_NULL_DOUBT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HUNTER_FRONTBAY_NULL_SCARED","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"HUNTER_FRONTBAY_NULL_DOUBT","text":{"KOREA":"문단속을 깜빡한 거겠지. 헛소리 할 시간에 빨리 담기나 해.","JPN":"鍵をかけるのを忘れたんだろ。余計なこと言ってねえで、さっさと詰めろよ。","ENG":"I bet he just forgot to lock it. Now, shut up and start grabbing everything you can.","TWN":"可能是忘記鎖門吧。廢話少說，趕緊裝東西。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HUNTER_FRONTBAY_NULL_DOUBT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HUNTER_FRONTBAY_NULL_SCARED","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"HUNTER_FRONTBAY_NULL_SCARED","text":{"KOREA":"응?","JPN":"ん？","ENG":"Huh?","TWN":"嗯？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HUNTER_FRONTBAY_NULL_SCARED","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"HUNTER_FRONTBAY_NULL_SCARED","text":{"KOREA":" 방금 저쪽 항아리가 움직인 것 같은데?","JPN":" 今、あっちのツボが動いたような？","ENG":"I think I just saw that jar move.","TWN":"那邊的罐子好像在動？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HUNTER_FRONTBAY_NULL_SCARED","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"PIRATE_FRONTBAY_NULL_STEAL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HUNTER_FRONTBAY_NULL_SCARED","face":"UNIT_IDLE"},"R":{"char_id":"PIRATE_FRONTBAY_NULL_STEAL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"HUNTER_FRONTBAY_NULL_SCARED","text":{"KOREA":"우와악!","JPN":"うわぁーっ！","ENG":"WHOA!","TWN":"哇啊啊！！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HUNTER_FRONTBAY_NULL_SCARED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIRATE_FRONTBAY_NULL_STEAL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"HUNTER_FRONTBAY_NULL_SCARED","text":{"KOREA":"해, 해적이 왜 여기에 있는 거야?!","JPN":"な、なんで海賊がここにいるんだ！？","ENG":"W-why are pirates here?!","TWN":"海…海盜怎麼會在這裡？！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HUNTER_FRONTBAY_NULL_SCARED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIRATE_FRONTBAY_NULL_STEAL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"PIRATE_FRONTBAY_NULL_LOOK","text":{"KOREA":"쳇, 걸렸나?","JPN":"ちっ、バレたか？","ENG":"Tch! We've been spotted.","TWN":"嘖，被發現了。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"PIRATE_FRONTBAY_NULL_LOOK","face":"UNIT_HATE"}}}},{"id":"L18_1","type":"dialog","speaker":"HUNTER_FRONTBAY_NULL_DOUBT","text":{"KOREA":"제길! 쏴 버려!","JPN":"くそ！　撃て！","ENG":"Dammit! Shoot 'em up!","TWN":"該死！快開槍！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HUNTER_FRONTBAY_NULL_DOUBT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIRATE_FRONTBAY_NULL_LOOK","face":"UNIT_HATE"}}}},{"id":"L20_1","type":"dialog","speaker":"PIRATE_FRONTBAY_NULL_STEAL","text":{"KOREA":"잠깐!","JPN":"待て！","ENG":"Wait!","TWN":"等等！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIRATE_FRONTBAY_NULL_STEAL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"PIRATE_FRONTBAY_NULL_STEAL","text":{"KOREA":"지금 소란 일으켜서 피차 좋을 거 없어. 부두 사람들을 전부 깨우려는 건 아니겠지?","JPN":"今騒ぎを起こしてもいいことはねえ。波止場の人たちを起こす気じゃないだろな？","ENG":"It won't end well for the both of us if we cause a ruckus. You don't want to wake up the others on the wharf, right?","TWN":"現在把事情鬧大對誰都沒有好處。你也不想把碼頭的人都吵醒吧？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIRATE_FRONTBAY_NULL_STEAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"HUNTER_FRONTBAY_NULL_SCARED","text":{"KOREA":"무, 무슨 헛수작을 부리려는 거야! 이 해적 놈이!","JPN":"な、何を無駄口叩いてるんだ！　この海賊め！","ENG":"W-what kind of game are you playin', huh?! You filthy pirate!","TWN":"休…休想耍手段！你這個臭海盜！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HUNTER_FRONTBAY_NULL_SCARED","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"PIRATE_FRONTBAY_NULL_STEAL","text":{"KOREA":"어차피 너희도 보물을 가지러 온 거잖아?","JPN":"どうせお前らも宝を盗みに来たんだろ？","ENG":"Aren't y'all here for the treasure too?","TWN":"反正你們也是來拿寶藏的吧？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIRATE_FRONTBAY_NULL_STEAL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"PIRATE_FRONTBAY_NULL_STEAL","text":{"KOREA":"어차피 혼자 가져갈 만한 양도 아니야. 각자 자기 몫을 챙겨서 떠나는 게 어때.","JPN":"どのみち一人で持っていける量じゃないんだ。それぞれの取り分を持っていくのはどうだ？","ENG":"There's enough to go around. How about we just take what we can and leave?","TWN":"這些東西你也無法全搬走，不如大家各拿各的，拿完就走。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIRATE_FRONTBAY_NULL_STEAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"HUNTER_FRONTBAY_NULL_DOUBT","text":{"KOREA":"뭐야, 해적 주제에 같은 해적 물건을 훔치러 온 거였어? 에이버리가 지옥에서 울겠구만.","JPN":"なんだ、海賊のくせに同じ海賊のものを盗みに来たのか？　エイバリーが地獄で泣くぜ。","ENG":"Huh? A pirate stealing from another pirate? Avery's gonna turn in his grave.","TWN":"什麼？你身為海盜，卻在這裡偷海盜的東西？艾維利泉下有知會哭的。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HUNTER_FRONTBAY_NULL_DOUBT","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"PIRATE_FRONTBAY_NULL_LOOK","text":{"KOREA":"크헤헤, 너희야말로 관리국 공인인 주제에 남의 뒷주머니를 털려던 거냐?","JPN":"クヘヘ、お前らこそ管理局公認のくせに、人のものをかっさらおうとしてたのかよ。","ENG":"Kehehe, coming from an officer of the Administration stealing from a pirate.","TWN":"嘿嘿，你們不也是管理局認可的獵人，卻在這裡偷別人的東西嗎？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIRATE_FRONTBAY_NULL_LOOK","face":"UNIT_LAUGH"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"HUNTER_FRONTBAY_NULL_DOUBT","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HUNTER_FRONTBAY_NULL_DOUBT","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"HUNTER_FRONTBAY_NULL_DOUBT","text":{"KOREA":"쳇, 할 수 없지. 5대5로 나눠.","JPN":"ちっ、仕方ねえな。5対5にしようぜ。","ENG":"Tch. Fine then. It'll be a 50/50 split.","TWN":"嘖，就這樣吧，我們五五分賬。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HUNTER_FRONTBAY_NULL_DOUBT","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"PIRATE_FRONTBAY_NULL_LOOK","text":{"KOREA":"좋아. 여기서 나간 뒤로는 서로 아는 체도 하지 말자고.","JPN":"いいだろう。ここを出た後は、互いに知らないふりだ。","ENG":"All right. And we're all gonna forget what happened as soon as we're outta here, got that?","TWN":"好，離開這裡後，我們誰也不認識誰。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HUNTER_FRONTBAY_NULL_DOUBT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIRATE_FRONTBAY_NULL_LOOK","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":null,"text":{"KOREA":"도둑들끼리 합의를 보다니, 보기 드문 광경이네.","JPN":"泥棒同志で示談とは、珍しい光景だ。","ENG":"Thieves collaborating... Now that's a rare sight to see.","TWN":"難得看到一群小偷達成協議呢。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HUNTER_FRONTBAY_NULL_DOUBT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIRATE_FRONTBAY_NULL_LOOK","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"PIRATE_FRONTBAY_NULL_LOOK","text":{"KOREA":"…응?","JPN":"……は？","ENG":"...Huh?","TWN":"…嗯？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HUNTER_FRONTBAY_NULL_DOUBT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIRATE_FRONTBAY_NULL_LOOK","face":"UNIT_SURPRISE"}}}},{"id":"L35_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"남이 목숨 걸고 구한 보물을 당신들끼리 그냥 꿀꺽하려고?","JPN":"人が命をかけて追い求めた宝を、あなたたちだけで独り占めする気？","ENG":"So you're just going to steal the treasure that another man risked his life for?","TWN":"你們就這樣把別人冒著生命危險找到的寶藏據為己有？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"HUNTER_FRONTBAY_NULL_SCARED","text":{"KOREA":"저 녀석은…? 보물사냥꾼과 돌아왔던 해적이잖아!","JPN":"あいつは……？　トレジャーハンターと一緒に帰ってきた海賊じゃねえか！","ENG":"Isn't that...? She's the pirate who came back with the treasure hunter!","TWN":"那個人…？她是和寶藏獵人一起回來的海盜！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HUNTER_FRONTBAY_NULL_SCARED","face":"UNIT_IDLE"},"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"PIRATE_FRONTBAY_NULL_LOOK","text":{"KOREA":"샤크스 해적단? 너도 있었냐?","JPN":"シャークス海賊団？　お前もいたのか？","ENG":"The Sharks? You're here too?","TWN":"大白鯊海盜團？你當時也在？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HUNTER_FRONTBAY_NULL_SCARED","face":"UNIT_IDLE"},"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"PIRATE_FRONTBAY_NULL_LOOK","face":"UNIT_HATE"}}}},{"id":"L38_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"어쩌다 보니, 그렇게 됐어.","JPN":"成り行きでね。","ENG":"Yeah, it appears so.","TWN":"雖然是巧合，不過確實是這樣。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HUNTER_FRONTBAY_NULL_SCARED","face":"UNIT_IDLE"},"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"PIRATE_FRONTBAY_NULL_LOOK","face":"UNIT_HATE"}}}},{"id":"L39_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"그거 얌전히 내려놓고 돌아가는 게 어때?","JPN":"それはおとなしく置いて帰ったらどうだ？","ENG":"How about you give that back and go your own ways?","TWN":"不如，你們乖乖放下東西回去吧？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HUNTER_FRONTBAY_NULL_SCARED","face":"UNIT_IDLE"},"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"PIRATE_FRONTBAY_NULL_LOOK","face":"UNIT_HATE"}}}},{"id":"L40_1","type":"dialog","speaker":"PIRATE_FRONTBAY_NULL_LOOK","text":{"KOREA":"흥, 그렇게 못하겠다면?","JPN":"ふん、できないと言ったら？","ENG":"Hmph. And what if I say no?","TWN":"哼，如果我說不呢？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HUNTER_FRONTBAY_NULL_SCARED","face":"UNIT_IDLE"},"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"PIRATE_FRONTBAY_NULL_LOOK","face":"UNIT_SERIOUS"}}}},{"id":"L41_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"싫다면 내가 뭐 별 수 있나.","JPN":"嫌なら仕方ない。","ENG":"Well, what else can I do?","TWN":"既然你不願意，那就別怪我囉。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HUNTER_FRONTBAY_NULL_SCARED","face":"UNIT_IDLE"},"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"PIRATE_FRONTBAY_NULL_LOOK","face":"UNIT_SERIOUS"}}}},{"id":"L43_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"샤크스 해적단 주방장의 풀코스. 달게 받아라.","JPN":"シャークス海賊団料理長のフルコース。喜んで受け取れ。","ENG":"This is the Sharks chef's full course. Let's see how you like what I've cooked up for you.","TWN":"好好享受，大白鯊海盜團主廚的全餐。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};